'use strict';

/**
 * Classify a Sequelize / generic error into { isUser, message, code }.
 * code is used for system errors only (e.g. 'SYS-042').
 */
function classifyError(err, sysCode) {
  if (!err) return { isUser: false, message: 'Unknown error', code: sysCode };

  const name = err.name || '';

  // Sequelize user-facing errors
  if (name === 'SequelizeUniqueConstraintError') {
    const field = err.errors?.[0]?.path || 'field';
    return { isUser: true, message: `A record with that ${field} already exists. Please use a different value.` };
  }
  if (name === 'SequelizeValidationError') {
    const msg = err.errors?.map(e => e.message).join('; ') || err.message;
    return { isUser: true, message: `Validation failed: ${msg}` };
  }
  if (name === 'SequelizeForeignKeyConstraintError') {
    return { isUser: true, message: 'This record references another record that no longer exists. Please refresh and try again.' };
  }
  if (name === 'SequelizeEmptyResultError') {
    return { isUser: true, message: 'The requested record was not found.' };
  }

  // System errors
  const message = err.message || String(err);
  return { isUser: false, message, code: sysCode };
}

/**
 * Send a properly-formatted error response.
 * Uses res.status(400) for user errors, res.status(500) for system errors.
 */
function sendError(res, err, sysCode) {
  const { isUser, message, code } = classifyError(err, sysCode);
  console.error(`[${code || 'USER-ERR'}]`, err);
  if (isUser) {
    return res.status(400).json({ type: 'user', message });
  }
  return res.status(500).json({ type: 'system', message, code });
}

module.exports = { classifyError, sendError };

