const jwt = require('jsonwebtoken');
const { verifyAzureToken, findOrCreateUser } = require('../services/auth.service');

const privateKey = process.env.JWT_PRIVATE_KEY;

/**
 * POST /auth/azure
 * Body: { idToken: <Azure AD ID token> }
 * Returns: { status: 'success', token: <Designflow JWT> }
 */
exports.azureCallback = async (req, res) => {
  try {
    const { idToken } = req.body;
    if (!idToken) {
      return res.status(400).json({ status: 'fail', message: 'idToken is required' });
    }

    const azurePayload = await verifyAzureToken(idToken);
    const user         = await findOrCreateUser(azurePayload);

    const tokenData = {
      name:    `${user.name || ''} ${user.lastname || ''}`.trim(),
      user_id: user.id,
      email:   user.email,
      role:    user.level,
    };
    if (user.level === 'vendor') {
      tokenData.factory_id = user.factory_id;
    }

    const token = jwt.sign(tokenData, privateKey, {
      algorithm: 'RS256',
      expiresIn: '12h',
    });

    return res.json({ status: 'success', token });
  } catch (err) {
    console.error('[auth/azure]', err.message);
    const isTokenError = ['JsonWebTokenError', 'TokenExpiredError', 'NotBeforeError']
      .includes(err.name);
    const message = isTokenError
      ? 'Invalid or expired Azure token'
      : 'Authentication failed';
    return res.status(401).json({ status: 'fail', message });
  }
};

'use strict';
const jwksClient = require('jwks-rsa');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcrypt');
const crypto = require('crypto');
const sql = require('../models/db');

const TENANT_ID = process.env.AZURE_TENANT_ID;
const CLIENT_ID = process.env.AZURE_CLIENT_ID;

// Lazy-init so tests can inject env before the module loads
let _jwks = null;
function getJwksClient() {
  if (!_jwks) {
    _jwks = jwksClient({
      jwksUri: `https://login.microsoftonline.com/${TENANT_ID}/discovery/v2.0/keys`,
      cache: true,
      cacheMaxEntries: 5,
      cacheMaxAge: 10 * 60 * 1000, // 10 min
    });
  }
  return _jwks;
}

function _getSigningKey(kid) {
  return new Promise((resolve, reject) => {
    getJwksClient().getSigningKey(kid, (err, key) => {
      if (err) return reject(err);
      resolve(key.getPublicKey());
    });
  });
}

/**
 * Validate an Azure AD ID token.
 * Returns the decoded payload on success; throws on failure.
 */
async function verifyAzureToken(idToken) {
  const decoded = jwt.decode(idToken, { complete: true });
  if (!decoded) throw new Error('Invalid token format');

  const signingKey = await _getSigningKey(decoded.header.kid);

  const payload = jwt.verify(idToken, signingKey, {
    algorithms: ['RS256'],
    audience: CLIENT_ID,
    issuer: `https://login.microsoftonline.com/${TENANT_ID}/v2.0`,
  });
  return payload;
}

/**
 * Look up an existing user by email, or auto-create one from Azure claims.
 * Returns a plain object with at least: id, name, lastname, email, level, userType.
 */
async function findOrCreateUser(azurePayload) {
  const email = (
    azurePayload.preferred_username ||
    azurePayload.email ||
    ''
  ).toLowerCase().trim();

  if (!email) throw new Error('No email found in Azure token claims');

  // 1 — Check internal users table
  const user = await sql.users.findOne({ where: { email } });
  if (user) return { ...user.dataValues, userType: 'user' };

  // 2 — Check vendor table
  const vendor = await sql.vendor.findOne({ where: { vendor_email: email } });
  if (vendor) {
    return {
      id: vendor.vendor_id,
      email: vendor.vendor_email,
      level: 'vendor',
      name: vendor.vendor_name,
      lastname: vendor.vendor_lastname,
      factory_id: vendor.factory_id_fk,
      userType: 'vendor',
    };
  }

  // 3 — Auto-provision: create a new internal user from Azure profile
  const nameParts = (azurePayload.name || email.split('@')[0]).split(' ');
  const firstName = azurePayload.given_name  || nameParts[0]                      || '';
  const lastName  = azurePayload.family_name || nameParts.slice(1).join(' ')      || '';
  const randomPass = await bcrypt.hash(crypto.randomUUID(), 12);
  const today = new Date().toISOString().split('T')[0];

  const newUser = await sql.users.create({
    name:     firstName,
    lastname: lastName,
    email,
    level:    'designer',   // default — admin can promote via User Management
    passw:    randomPass,
    status:   'active',
    adddate:  today,
  });

  return { ...newUser.dataValues, userType: 'user' };
}

module.exports = { verifyAzureToken, findOrCreateUser };

